parameters.jsCode:
const candidates = $json.candidates || [];
const text = candidates?.[0]?.content?.parts?.[0]?.text || '';

// Try to extract JSON from the response
let socialPosts = {};
try {
  const jsonMatch = text.match(/```json\n?([\s\S]*?)\n?```/);
  if (jsonMatch) {
    socialPosts = JSON.parse(jsonMatch[1]);
  } else {
    socialPosts = JSON.parse(text);
  }
} catch (e) {
  socialPosts = {
    raw_output: text,
    twitter_thread: text.slice(0, 500),
    linkedin: text.slice(500, 1000),
    instagram: text.slice(1000, 1500),
    tiktok: text.slice(1500, 2000)
  };
}

const prevData = $('Parse Content Input').first().json;
return [{
  json: {
    blog_url: prevData.blog_url,
    blog_title: prevData.blog_title,
    target_platforms: prevData.target_platforms,
    tone: prevData.tone,
    twitter_thread: socialPosts.twitter_thread || '',
    linkedin_post: socialPosts.linkedin || '',
    instagram_caption: socialPosts.instagram || '',
    tiktok_script: socialPosts.tiktok || '',
    raw_output: text
  }
}];
